     1→import { trackSeverinoEvent } from "@/services/severinoService";
     2→import { EasySalonLayout } from "@/components/layout/EasySalonLayout";
     3→import { ConfirmCancelModal } from "@/components/modals/ConfirmCancelModal";
     4→import { CreateSolicitacaoModal } from "@/components/modals/CreateSolicitacaoModal";
     5→import { TransformarSolicitacaoModal } from "@/components/modals/TransformarSolicitacaoModal";
     6→import { SolicitacaoKanban } from "@/components/solicitacoes/SolicitacaoKanban";
     7→import { Badge } from "@/components/ui/badge";
     8→import { Button } from "@/components/ui/button";
     9→import { Calendar } from "@/components/ui/calendar";
    10→import { Popover, PopoverContent, PopoverTrigger } from "@/components/ui/popover";
    11→import { Skeleton } from "@/components/ui/skeleton";
    12→import { getSalonNavItems } from "@/config/navigation";
    13→import { useAuth } from "@/contexts/AuthContext";
    14→import { useToast } from "@/hooks/use-toast";
    15→import { useSelectedSalon } from "@/hooks/useSelectedSalon";
    16→import { cn } from "@/lib/utils";
    17→import {
    18→  ConvertToAppointmentDto,
    19→  KanbanDataResponse,
    20→  requestsService,
    21→  UpdateStatusDto,
    22→} from "@/services/requestsService";
    23→import { websocketService } from "@/services/websocketService";
    24→import {
    25→  SolicitacaoColumn,
    26→  SolicitacaoItem,
    27→  SolicitacaoStatus,
    28→} from "@/types/solicitacoes";
    29→import { addMonths, endOfDay, format, startOfDay, subDays } from "date-fns";
    30→import { ptBR } from "date-fns/locale";
    31→import { Calendar as CalendarIcon, ClipboardList as ClipboardList, RefreshCw as RefreshCw, X as X, Phone as Phone, User as UserIcon, Clock as Clock } from "lucide-react";
    32→import {
    33→  Tabs,
    34→  TabsContent,
    35→  TabsList,
    36→  TabsTrigger
    37→} from "@/components/ui/tabs";
    38→import { useEffect, useState } from "react";
    39→import { analytics } from "@/lib/analytics";
    40→
    41→interface ConvertToAppointmentData {
    42→  appointmentDate: string;
    43→  appointmentTime: string;
    44→  professionalId: string;
    45→  serviceId: string;
    46→  clientId: string;
    47→  duration: number;
    48→  price: number;
    49→  observations?: string;
    50→}
    51→
    52→interface UpdateStatusData {
    53→  status: SolicitacaoStatus;
    54→  finalDate?: string;
    55→  finalTime?: string;
    56→}
    57→
    58→interface ErrorResponse {
    59→  response?: {
    60→    data?: {
    61→      message?: string;
    62→    };
    63→  };
    64→}
    65→
    66→export default function SolicitacoesPage(): JSX.Element {
    67→  const { selectedSalon } = useSelectedSalon();
    68→  const { toast } = useToast();
    69→  const { user } = useAuth();
    70→  const [kanbanData, setKanbanData] = useState<KanbanDataResponse | null>(null);
    71→  const [loading, setLoading] = useState(true);
    72→  const [refreshing, setRefreshing] = useState(false);
    73→
    74→  // Estados para filtro de data
    75→  const [startDate, setStartDate] = useState<Date | undefined>(new Date());
    76→  const [endDate, setEndDate] = useState<Date | undefined>(addMonths(new Date(), 3));
    77→  const [startDateOpen, setStartDateOpen] = useState(false);
    78→  const [endDateOpen, setEndDateOpen] = useState(false);
    79→
    80→  const navItems = getSalonNavItems(user?.role || "Profissional");
    81→
    82→  useEffect(() => {
    83→    analytics.trackEvent("requests_page_viewed", { booking_source: 'dashboard' as any });
    84→  }, []);
    85→  const [selectedSolicitacao, setSelectedSolicitacao] =
    86→    useState<SolicitacaoItem | null>(null);
    87→  const [isModalOpen, setIsModalOpen] = useState(false);
    88→  const [isCreateModalOpen, setIsCreateModalOpen] = useState(false);
    89→  const [isCancelModalOpen, setIsCancelModalOpen] = useState(false);
    90→  const [itemToCancel, setItemToCancel] = useState<{
    91→    id: string;
    92→    name: string;
    93→  } | null>(null);
    94→
    95→  const loadData = async (): Promise<void> => {
    96→    try {
    97→      setRefreshing(true);
    98→
    99→      // Preparar parâmetros de filtro
   100→      const params: { startDate?: string; endDate?: string } = {};
   101→
   102→      if (startDate) {
   103→        params.startDate = format(startOfDay(startDate), "yyyy-MM-dd");
   104→      }
   105→      if (endDate) {
   106→        params.endDate = format(endOfDay(endDate), "yyyy-MM-dd");
   107→      }
   108→
   109→      const data = await requestsService.getKanbanData(params);
   110→      setKanbanData(data);
   111→    } catch (error) {
   112→      toast({
   113→        title: "Erro ao carregar solicitações",
   114→        description:
   115→          "Não foi possível carregar as solicitações. Tente novamente.",
   116→        variant: "destructive",
   117→      });
   118→    } finally {
   119→      setLoading(false);
   120→      setRefreshing(false);
   121→    }
   122→  };
   123→
   124→  const handleClearFilters = () => {
   125→    setStartDate(subDays(new Date(), 7));
   126→    setEndDate(new Date());
   127→  };
   128→
   129→  const handleStartDateSelect = (date: Date | undefined) => {
   130→    setStartDate(date);
   131→    setStartDateOpen(false);
   132→  };
   133→
   134→  const handleEndDateSelect = (date: Date | undefined) => {
   135→    setEndDate(date);
   136→    setEndDateOpen(false);
   137→  };
   138→
   139→  useEffect(() => {
   140→    loadData();
   141→
   142→    const handleRequestCreated = (): void => {
   143→      loadData();
   144→      toast({
   145→        title: "Nova solicitação",
   146→        description: "Uma nova solicitação foi criada.",
   147→      });
   148→    };
   149→
   150→    const handleRequestUpdated = (): void => {
   151→      loadData();
   152→    };
   153→
   154→    const handleRequestDeleted = (): void => {
   155→      loadData();
   156→    };
   157→
   158→    const handleRequestStatusChanged = (): void => {
   159→      loadData();
   160→    };
   161→
   162→    const unsubscribeCreated = websocketService.on(
   163→      "request:created",
   164→      handleRequestCreated
   165→    );
   166→    const unsubscribeUpdated = websocketService.on(
   167→      "request:updated",
   168→      handleRequestUpdated
   169→    );
   170→    const unsubscribeDeleted = websocketService.on(
   171→      "request:deleted",
   172→      handleRequestDeleted
   173→    );
   174→    const unsubscribeStatusUpdated = websocketService.on(
   175→      "request:status_updated",
   176→      handleRequestStatusChanged
   177→    );
   178→    const unsubscribeConverted = websocketService.on(
   179→      "request:converted",
   180→      handleRequestUpdated
   181→    );
   182→    const unsubscribeAssigned = websocketService.on(
   183→      "request:assigned",
   184→      handleRequestUpdated
   185→    );
   186→
   187→    return (): void => {
   188→      unsubscribeCreated();
   189→      unsubscribeUpdated();
   190→      unsubscribeDeleted();
   191→      unsubscribeStatusUpdated();
   192→      unsubscribeConverted();
   193→      unsubscribeAssigned();
   194→    };
   195→  }, [startDate, endDate]); // Recarregar quando as datas mudarem
   196→
   197→  const columns: SolicitacaoColumn[] =
   198→    kanbanData?.columns.map((col) => ({
   199→      id: col.id as SolicitacaoStatus,
   200→      title: col.title,
   201→      items: col.items,
   202→    })) || [];
   203→
   204→  // Estatísticas
   205→  const stats = kanbanData?.stats || {
   206→    total: 0,
   207→    abertas: 0,
   208→    agendadas: 0,
   209→  };
   210→
   211→  const handleMoveItem = async (
   212→    itemId: string,
   213→    fromColumn: string,
   214→    toColumn: string
   215→  ): Promise<void> => {
   216→    // Se está movendo de "open" para "scheduled", abrir modal de agendamento
   217→    if (fromColumn === "open" && toColumn === "scheduled") {
   218→      // Encontrar o item sendo movido
   219→      const movedItem = kanbanData?.columns
   220→        .find((c) => c.id === fromColumn)
   221→        ?.items.find((item) => item.id === itemId);
   222→
   223→      if (movedItem) {
   224→        // Abrir modal para transformar em agendamento
   225→        setSelectedSolicitacao(movedItem);
   226→        setIsModalOpen(true);
   227→      }
   228→      return;
   229→    }
   230→
   231→    // Se está movendo para "cancelled" ou variações em português, abrir modal de confirmação
   232→    if (
   233→      (toColumn === "cancelled" ||
   234→        toColumn === "cancelado" ||
   235→        toColumn === "cancelados") &&
   236→      (fromColumn === "open" || fromColumn === "scheduled")
   237→    ) {
   238→      const movedItem = kanbanData?.columns
   239→        .find((c) => c.id === fromColumn)
   240→        ?.items.find((item) => item.id === itemId);
   241→
   242→      if (movedItem) {
   243→        // Configurar item para cancelar e abrir modal de confirmação
   244→        setItemToCancel({
   245→          id: itemId,
   246→          name:
   247→            movedItem.customerName ||
   248→            movedItem.serviceName ||
   249→            "esta solicitação",
   250→        });
   251→        setIsCancelModalOpen(true);
   252→      }
   253→      return;
   254→    }
   255→
   256→    // Para outros movimentos, não permitir
   257→    toast({
   258→      title: "Ação não permitida",
   259→      description: "Esta operação não é permitida.",
   260→      variant: "destructive",
   261→    });
   262→  };
   263→
   264→  const handleItemClick = (item: SolicitacaoItem): void => {
   265→    if (item.status === "open") {
   266→      setSelectedSolicitacao(item);
   267→      setIsModalOpen(true);
   268→    }
   269→  };
   270→
   271→  const handleSaveSolicitacao = async (
   272→    updatedSolicitacao: SolicitacaoItem
   273→  ): Promise<void> => {
   274→    try {
   275→      if (
   276→        updatedSolicitacao.status === "scheduled" &&
   277→        updatedSolicitacao.assignedProfessionalId &&
   278→        updatedSolicitacao.finalDate &&
   279→        updatedSolicitacao.finalTime
   280→      ) {
   281→        try {
   282→          const appointmentDateStr = updatedSolicitacao.finalDate
   283→            ? format(new Date(updatedSolicitacao.finalDate), "yyyy-MM-dd")
   284→            : "";
   285→
   286→          const convertData: ConvertToAppointmentDto = {
   287→            appointmentDate: appointmentDateStr,
   288→            appointmentTime: updatedSolicitacao.finalTime,
   289→            professionalId: updatedSolicitacao.assignedProfessionalId,
   290→            serviceId: updatedSolicitacao.serviceId,
   291→            clientId: updatedSolicitacao.clientId,
   292→            duration: updatedSolicitacao.duration,
   293→            price: updatedSolicitacao.price,
   294→            observations: updatedSolicitacao.observations,
   295→          };
   296→
   297→          await requestsService.convertToAppointment(
   298→            updatedSolicitacao.id,
   299→            convertData
   300→          );
   301→
   302→          await loadData();
   303→
   304→          toast({
   305→            title: "Agendamento criado",
   306→            description: `Solicitação convertida em agendamento com sucesso.`,
   307→          });
   308→
   309→          analytics.trackEvent("request_approved", { booking_source: 'dashboard' as any });
   310→        } catch (error) {
   311→          const errorResponse = error as ErrorResponse;
   312→
   313→          if (errorResponse?.response?.data?.message?.includes("performedBy")) {
   314→            // eslint-disable-next-line no-useless-catch
   315→            try {
   316→              const statusData: UpdateStatusDto = {
   317→                status: "scheduled",
   318→                finalDate: updatedSolicitacao.finalDate,
   319→                finalTime: updatedSolicitacao.finalTime,
   320→              };
   321→
   322→              await requestsService.updateStatus(
   323→                updatedSolicitacao.id,
   324→                statusData
   325→              );
   326→
   327→              await loadData();
   328→
   329→              toast({
   330→                title: "Status atualizado",
   331→                description: `Solicitação marcada como agendada. Por favor, crie o agendamento manualmente na agenda.`,
   332→                variant: "default",
   333→              });
   334→            } catch (statusError) {
   335→              throw statusError;
   336→            }
   337→          } else {
   338→            throw error;
   339→          }
   340→        }
   341→      } else {
   342→        await requestsService.update(updatedSolicitacao.id, updatedSolicitacao);
   343→        await loadData();
   344→
   345→        toast({
   346→          title: "Solicitação atualizada",
   347→          description: "As informações foram salvas com sucesso.",
   348→        });
   349→      }
   350→    } catch (error) {
   351→      toast({
   352→        title: "Erro ao salvar",
   353→        description: "Não foi possível salvar as alterações. Tente novamente.",
   354→        variant: "destructive",
   355→      });
   356→    }
   357→  };
   358→
   359→  const handleCreateSolicitacao = async (
   360→    data: Partial<SolicitacaoItem>
   361→  ): Promise<void> => {
   362→    try {
   363→      await requestsService.create(data);
   364→      await loadData();
   365→
   366→      toast({
   367→        title: "Solicitação criada",
   368→        description: "A solicitação foi criada com sucesso.",
   369→      });
   370→
   371→      trackSeverinoEvent('solicitacao_de_agendamento', { description: 'Solicitação de agendamento criada' });
   372→    } catch (error) {
   373→      toast({
   374→        title: "Erro ao criar",
   375→        description: "Não foi possível criar a solicitação. Tente novamente.",
   376→        variant: "destructive",
   377→      });
   378→    }
   379→  };
   380→
   381→  if (loading) {
   382→    return (
   383→      <EasySalonLayout
   384→        sideNavTitle={selectedSalon?.name || "Meu Salão"}
   385→        sideNavSubtitle={selectedSalon?.name || "Meu Salão"}
   386→        sideNavItems={navItems}
   387→      >
   388→        <div className="space-y-6">
   389→          <div className="grid grid-cols-1 md:grid-cols-3 gap-4">
   390→            {[1, 2, 3].map((i) => (
   391→              <div key={i} className="bg-card border border-border rounded-3xl p-4">
   392→                <Skeleton className="h-12 w-full" />
   393→              </div>
   394→            ))}
   395→          </div>
   396→          <Skeleton className="h-96 w-full" />
   397→        </div>
   398→      </EasySalonLayout>
   399→    );
   400→  }
   401→
   402→  return (
   403→    <EasySalonLayout
   404→      sideNavTitle={selectedSalon?.name || "Meu Salão"}
   405→      sideNavSubtitle={selectedSalon?.name || "Meu Salão"}
   406→      sideNavItems={navItems}
   407→    >
   408→      <div className="space-y-4 md:space-y-6">
   409→        {/* Header with actions */}
   410→        <div className="flex justify-between items-center bg-card p-4 md:p-0 rounded-lg md:bg-transparent shadow-sm md:shadow-none">
   411→          <h1 className="text-xl md:text-2xl font-bold text-foreground">Solicitações</h1>
   412→          <div className="flex gap-2">
   413→            <Button
   414→              variant="outline"
   415→              size="sm"
   416→              onClick={loadData}
   417→              disabled={refreshing}
   418→              className=""
   419→            >
   420→              <RefreshCw
   421→                className={cn("h-4 w-4 mr-2", refreshing && "animate-spin")}
   422→              />
   423→              <span className="hidden sm:inline">Atualizar</span>
   424→            </Button>
   425→          </div>
   426→        </div>
   427→
   428→        {/* Filtros de Data - Compacto no Mobile */}
   429→        <div className="md:bg-card md:border md:border-border md:rounded-3xl">
   430→          <div className="p-0 md:p-4">
   431→            <div className="flex flex-col gap-3 p-4 md:p-0">
   432→              <div className="flex flex-row items-center gap-2 flex-wrap text-sm">
   433→                <div className="flex items-center gap-2 bg-muted/30 p-1.5 rounded-lg border">
   434→                  <Popover open={startDateOpen} onOpenChange={setStartDateOpen}>
   435→                    <PopoverTrigger asChild>
   436→                      <button className="flex items-center gap-2 px-2 py-1 font-medium text-foreground">
   437→                        <CalendarIcon className="h-4 w-4 text-primary" />
   438→                        {startDate ? format(startDate, "dd/MM/yy") : "Início"}
   439→                      </button>
   440→                    </PopoverTrigger>
   441→                    <PopoverContent className="w-auto p-0" align="start">
   442→                      <Calendar
   443→                        mode="single"
   444→                        selected={startDate}
   445→                        onSelect={handleStartDateSelect}
   446→                        initialFocus
   447→                        locale={ptBR}
   448→                      />
   449→                    </PopoverContent>
   450→                  </Popover>
   451→
   452→                  <span className="text-muted-foreground font-light text-xs">até</span>
   453→
   454→                  <Popover open={endDateOpen} onOpenChange={setEndDateOpen}>
   455→                    <PopoverTrigger asChild>
   456→                      <button className="flex items-center gap-2 px-2 py-1 font-medium text-foreground">
   457→                        <CalendarIcon className="h-4 w-4 text-primary" />
   458→                        {endDate ? format(endDate, "dd/MM/yy") : "Fim"}
   459→                      </button>
   460→                    </PopoverTrigger>
   461→                    <PopoverContent className="w-auto p-0" align="start">
   462→                      <Calendar
   463→                        mode="single"
   464→                        selected={endDate}
   465→                        onSelect={handleEndDateSelect}
   466→                        initialFocus
   467→                        locale={ptBR}
   468→                      />
   469→                    </PopoverContent>
   470→                  </Popover>
   471→                </div>
   472→
   473→                <Button
   474→                  variant="ghost"
   475→                  size="sm"
   476→                  onClick={handleClearFilters}
   477→                  className="h-9 px-2 text-muted-foreground hover:text-destructive"
   478→                >
   479→                  <X className="h-4 w-4 mr-1" />
   480→                  Limpar
   481→                </Button>
   482→              </div>
   483→
   484→              {startDate && endDate && (
   485→                <div className="text-xs text-muted-foreground pl-1">
   486→                  Mostrando solicitações de <span className="font-semibold text-foreground">{format(startDate, "dd/MM/yyyy")}</span> até <span className="font-semibold text-foreground">{format(endDate, "dd/MM/yyyy")}</span>
   487→                </div>
   488→              )}
   489→            </div>
   490→          </div>
   491→        </div>
   492→
   493→        {/* Mobile View: Tabs + Lista */}
   494→        <div className="block md:hidden">
   495→          <Tabs defaultValue="open" className="w-full">
   496→            <TabsList className="w-full grid grid-cols-3 h-14 p-1.5 bg-muted/20 rounded-lg border border-border/50">
   497→              <TabsTrigger
   498→                value="open"
   499→                className="relative rounded-xl data-[state=active]:bg-red-50 data-[state=active]:text-red-700 data-[state=active]:border-red-200 data-[state=active]:shadow-sm border border-transparent transition-all"
   500→              >
   501→                Abertas
   502→                {stats.abertas > 0 && (
   503→                  <Badge variant="destructive" className="absolute -top-1.5 -right-1.5 h-5 min-w-5 flex items-center justify-center p-0.5 text-[10px] font-bold border-2 border-white">
   504→                    {stats.abertas}
   505→                  </Badge>
   506→                )}
   507→              </TabsTrigger>
   508→              <TabsTrigger
   509→                value="scheduled"
   510→                className="relative rounded-xl data-[state=active]:bg-green-50 data-[state=active]:text-green-700 data-[state=active]:border-green-200 data-[state=active]:shadow-sm border border-transparent transition-all"
   511→              >
   512→                Agendadas
   513→                {stats.agendadas > 0 && (
   514→                  <Badge className="absolute -top-1.5 -right-1.5 h-5 min-w-5 flex items-center justify-center p-0.5 text-[10px] font-bold bg-green-500 text-white border-2 border-white">
   515→                    {stats.agendadas}
   516→                  </Badge>
   517→                )}
   518→              </TabsTrigger>
   519→              <TabsTrigger
   520→                value="cancelled"
   521→                className="rounded-xl data-[state=active]:bg-muted data-[state=active]:text-muted-foreground data-[state=active]:border-border data-[state=active]:shadow-sm border border-transparent transition-all"
   522→              >
   523→                Canceladas
   524→              </TabsTrigger>
   525→            </TabsList>
   526→
   527→            <TabsContent value="open" className="mt-4 space-y-3">
   528→              {columns.find(c => c.id === 'open')?.items.map(item => (
   529→                <RequestMobileCard
   530→                  key={item.id}
   531→                  item={item}
   532→                  status="open"
   533→                  onClick={() => handleItemClick(item)}
   534→                />
   535→              ))}
   536→              {columns.find(c => c.id === 'open')?.items.length === 0 && (
   537→                <EmptyState message="Nenhuma solicitação aberta." />
   538→              )}
   539→            </TabsContent>
   540→
   541→            <TabsContent value="scheduled" className="mt-4 space-y-3">
   542→              {columns.find(c => c.id === 'scheduled')?.items.map(item => (
   543→                <RequestMobileCard
   544→                  key={item.id}
   545→                  item={item}
   546→                  status="scheduled"
   547→                  onClick={() => handleItemClick(item)}
   548→                />
   549→              ))}
   550→              {columns.find(c => c.id === 'scheduled')?.items.length === 0 && (
   551→                <EmptyState message="Nenhuma solicitação agendada." />
   552→              )}
   553→            </TabsContent>
   554→
   555→            <TabsContent value="cancelled" className="mt-4 space-y-3">
   556→              {columns.find(c => c.id === 'cancelled' || c.id === 'cancelado')?.items.map(item => (
   557→                <RequestMobileCard
   558→                  key={item.id}
   559→                  item={item}
   560→                  status="cancelled"
   561→                  onClick={() => { }}
   562→                />
   563→              ))}
   564→              {(columns.find(c => c.id === 'cancelled' || c.id === 'cancelado')?.items.length || 0) === 0 && (
   565→                <EmptyState message="Nenhuma solicitação cancelada." />
   566→              )}
   567→            </TabsContent>
   568→          </Tabs>
   569→        </div>
   570→
   571→        {/* Desktop View: Stats + Kanban */}
   572→        <div className="hidden md:block space-y-6">
   573→          {/* Estatísticas */}
   574→          <div className="grid grid-cols-3 gap-4">
   575→            <StatsCard label="Total" value={stats.total} icon={ClipboardList} color="text-muted-foreground" />
   576→            <StatsCard label="Abertas" value={stats.abertas} icon={null} color="text-red-600" badgeColor="bg-red-100 text-red-800" badgeValue={stats.abertas} />
